glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uScale;
uniform float uContrast;
uniform float uSeed;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)) + uSeed * 17.0) * 43758.5453123); }
float noise(vec2 p){
 vec2 i = floor(p), f = fract(p);
 float a = hash(i), b = hash(i + vec2(1.0,0.0)), c = hash(i + vec2(0.0,1.0)), d = hash(i + vec2(1.0,1.0));
 vec2 u = f * f * (3.0 - 2.0 * f);
 return mix(a,b,u.x) + (c-a)*u.y*(1.0-u.x) + (d-b)*u.x*u.y;
}
float fbm(vec2 p){
 float v = 0.0;
 float a = 0.5;
 for(int i=0;i<5;i++){
 v += a * noise(p);
 p = p * 2.03 + vec2(17.2, 9.4);
 a *= 0.5;
 }
 return v;
}
void main(){
 vec2 uv = vUv;
 vec2 p = (uv - 0.5) * vec2(1.0, 1.35) * uScale;
 float n1 = fbm(p * 2.2);
 float n2 = fbm((p + vec2(3.1,-1.7)) * 5.5);
 float drag = smoothstep(-0.9, 0.9, uv.y + 0.06 * sin(uv.x * 8.0 + n1 * 4.0));
 vec3 base = vec3(0.906, 0.847, 0.722);
 vec3 ochre = vec3(0.831, 0.643, 0.337);
 vec3 clay = vec3(0.776, 0.494, 0.282);
 vec3 color = base;
 color = mix(color, ochre, 0.18 * n1);
 color = mix(color, clay, 0.12 * n2 * drag);
 float vignette = 1.0 - 0.16 * length((uv - 0.5) * vec2(1.1, 1.0));
 float paper = 0.92 + 0.08 * noise(uv * 140.0);
 color *= vignette * paper;
 color = mix(vec3(0.94,0.90,0.80), color, uContrast);
 gl_FragColor = vec4(color, 1.0);
}

