glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uHeight;
uniform float uWidth;
uniform float uSeed;
float hash(vec2 p){ return fract(sin(dot(p, vec2(91.7,233.1)) + uSeed * 13.0) * 43758.5453); }
float noise(vec2 p){
 vec2 i = floor(p), f = fract(p);
 float a = hash(i), b = hash(i + vec2(1.0,0.0)), c = hash(i + vec2(0.0,1.0)), d = hash(i + vec2(1.0,1.0));
 vec2 u = f*f*(3.0-2.0*f);
 return mix(a,b,u.x) + (c-a)*u.y*(1.0-u.x) + (d-b)*u.x*u.y;
}
float sdEllipse(vec2 p, vec2 ab){
 p /= ab;
 return length(p) - 1.0;
}
void main(){
 vec2 uv = vUv;
 vec2 p = uv - 0.5;
 p.y *= 1.55 / uHeight;
 p.x *= 1.1 / uWidth;
 float body = sdEllipse(p, vec2(0.28, 0.46));
 float edgeNoise = (noise(uv * 22.0) - 0.5) * 0.03;
 float alpha = 1.0 - smoothstep(-0.02 + edgeNoise, 0.03 + edgeNoise, body);
 float inner = 1.0 - smoothstep(-0.16, 0.22, body);
 float y1 = smoothstep(0.18, 0.16, abs(uv.y - 0.33));
 float y2 = smoothstep(0.18, 0.16, abs(uv.y - 0.50));
 float y3 = smoothstep(0.18, 0.16, abs(uv.y - 0.67));
 float chamberBands = max(max(y1,y2),y3) * inner;
 float verticalGlow = smoothstep(0.48, 0.0, abs(uv.x - 0.5)) * inner;
 vec3 terracotta = vec3(0.776, 0.353, 0.227);
 vec3 amber = vec3(0.855, 0.643, 0.231);
 vec3 cream = vec3(0.953, 0.898, 0.800);
 vec3 color = terracotta;
 color = mix(color, amber, 0.26 * verticalGlow);
 color = mix(color, cream, 0.19 * chamberBands);
 float vein = noise(uv * vec2(8.0, 32.0));
 color *= 0.9 + 0.14 * vein;
 float chamberCarve = (smoothstep(0.11, 0.0, abs(uv.y - 0.33)) + smoothstep(0.11, 0.0, abs(uv.y - 0.50)) + smoothstep(0.11, 0.0, abs(uv.y - 0.67))) * 0.12 * inner;
 color -= chamberCarve;
 gl_FragColor = vec4(color, alpha * 0.96);
}

