glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uBias;
uniform float uSeed;
float curveBand(float x, float y, float side, float offset, float width){
 float cx = mix(0.17, 0.83, side);
 float cy = 0.5 + offset;
 float r = length(vec2((x - cx) * 1.15, (y - cy) * 0.8));
 return smoothstep(width, width - 0.02, abs(r - 0.26));
}
void main(){
 vec2 uv = vUv;
 float leftA = curveBand(uv.x, uv.y, 0.0, -0.07, 0.04);
 float leftB = curveBand(uv.x, uv.y, 0.0, 0.12, 0.03);
 float rightA = curveBand(uv.x, uv.y, 1.0, 0.03, 0.035);
 float rightB = curveBand(uv.x, uv.y, 1.0, -0.14, 0.028);
 float maskL = smoothstep(0.46, 0.08, uv.x);
 float maskR = smoothstep(0.54, 0.92, uv.x);
 float signal = (leftA * 0.9 + leftB * 0.55) * maskL * uBias + (rightA * 0.75 + rightB * 0.45) * maskR * (1.15 - uBias);
 vec3 gold = vec3(0.812, 0.643, 0.298);
 vec3 rust = vec3(0.694, 0.396, 0.243);
 vec3 color = mix(rust, gold, smoothstep(0.1, 0.8, uv.y));
 float alpha = signal * 0.52;
 gl_FragColor = vec4(color, alpha);
}

