glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uBlueMix;
void main(){
 vec2 p = vUv - 0.5;
 float r = length(p);
 float disc = 1.0 - smoothstep(0.16, 0.19, r);
 float ring = smoothstep(0.12, 0.11, abs(r - 0.105));
 float core = smoothstep(0.05, 0.0, r);
 vec3 blue = vec3(0.427, 0.561, 0.722);
 vec3 gold = vec3(0.820, 0.690, 0.420);
 vec3 cream = vec3(0.95, 0.91, 0.82);
 vec3 color = mix(gold, blue, uBlueMix * 0.7);
 color = mix(color, cream, core * 0.45);
 color += ring * 0.08;
 float alpha = disc * 0.86 + ring * 0.14;
 gl_FragColor = vec4(color, alpha);
}
